    FINDING_CATEGORY_SECRETS = 'FINDING_CATEGORY_SECRETS'
    FINDING_CATEGORY_MALWARE = 'FINDING_CATEGORY_MALWARE'
    FINDING_CATEGORY_CICD = 'FINDING_CATEGORY_CICD'
